let floorNum = env.get("FLOOR");
let fStr = "f" + String(floorNum).padStart(2, "0");
let payload = msg.payload;
if (typeof payload === "string") {
    try { payload = JSON.parse(payload); }
    catch(e) { node.warn("Could not parse payload: " + payload); return null; }
}
let sensorId = payload.metadata && payload.metadata.sensor_id;
if (!sensorId) {
    node.warn("Missing metadata.sensor_id");
    return null;
}
let roomID = sensorId.split("-")[2];
msg.topic   = `campus/b01/${fStr}/${roomID}/telemetry`;
msg.payload = payload;
return msg;

// ── Desired vs Reported Sync ──────────────────────────────
let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch(e) { return msg; }
}
let sensorId = payload.metadata && payload.metadata.sensor_id;
if (!sensorId) { return msg; }

// Load desired state store {sensorId: {hvac_mode, lighting_dimmer, ts}}
let desired = flow.get('desiredState') || {};
let reported = flow.get('reportedState') || {};

// Update reported state with latest telemetry
reported[sensorId] = {
    hvac_mode:       payload.actuators && payload.actuators.hvac_mode,
    lighting_dimmer: payload.actuators && payload.actuators.lighting_dimmer,
    last_seen:       Math.floor(Date.now() / 1000)
};
flow.set('reportedState', reported);

// Check if there is a pending desired state for this room
let roomDesired = desired[sensorId];
if (!roomDesired) { return msg; }  // no pending desired — pass through

let roomReported = reported[sensorId];
let outOfSync = false;

// Compare desired vs reported
if (roomDesired.hvac_mode && roomDesired.hvac_mode !== roomReported.hvac_mode) {
    outOfSync = true;
}
if (roomDesired.lighting_dimmer !== undefined &&
    roomDesired.lighting_dimmer !== roomReported.lighting_dimmer) {
    outOfSync = true;
}

if (outOfSync) {
    node.warn('SYNC: ' + sensorId + ' out of sync — pushing desired state');

    // Build sync commands to push desired state to the node
    let syncMsgs = [];
    let floorId  = env.get('FLOOR');
    let fStr     = 'f' + String(floorId).padStart(2, '0');
    let roomID   = sensorId.split('-')[2];
    let cmdTopic = `campus/b01/${fStr}/${roomID}/cmd`;

    if (roomDesired.hvac_mode && roomDesired.hvac_mode !== roomReported.hvac_mode) {
        syncMsgs.push({
            topic:   cmdTopic,
            payload: JSON.stringify({
                command_id:    'sync-' + Date.now(),
                target_device: sensorId,
                action:        'SET_HVAC',
                value:         roomDesired.hvac_mode,
                timestamp:     Math.floor(Date.now() / 1000),
                source:        'desired_sync'
            })
        });
    }
    if (roomDesired.lighting_dimmer !== undefined &&
        roomDesired.lighting_dimmer !== roomReported.lighting_dimmer) {
        syncMsgs.push({
            topic:   cmdTopic,
            payload: JSON.stringify({
                command_id:    'sync-dimmer-' + Date.now(),
                target_device: sensorId,
                action:        'SET_DIMMER',
                value:         roomDesired.lighting_dimmer,
                timestamp:     Math.floor(Date.now() / 1000),
                source:        'desired_sync'
            })
        });
    }

    // Send each sync command
    syncMsgs.forEach(function(m) { node.send([msg, m]); });
    return null;  // hold original message — sync command takes priority
}

return msg;  // in sync — pass through to avg calculator

let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch(e) { return msg; }
}
let occupancy = payload.sensors && payload.sensors.occupancy;
let sensorId  = payload.metadata && payload.metadata.sensor_id;
let floorId   = env.get('FLOOR');
let fStr      = 'f' + String(floorId).padStart(2, '0');
if (!sensorId) { return msg; }
let roomID = sensorId.split('-')[2];
if (!occupancy) {
    node.send([msg, {
        topic:   `campus/b01/${fStr}/${roomID}/cmd`,
        payload: JSON.stringify({
            command_id:    'auto-' + Date.now(),
            target_device: sensorId,
            action:        'SET_HVAC',
            value:         'OFF',
            source:        'edge_autonomy'
        })
    }]);
    return null;
}
return msg;

let store   = flow.get('floorReadings') || {};
let floorId = env.get('FLOOR') || 4;
let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); }
    catch(e) { return null; }
}
let sensorId = payload.metadata && payload.metadata.sensor_id;
if (!sensorId) { return null; }
store[sensorId] = payload;
flow.set('floorReadings', store);
let roomCount = Object.keys(store).length;
if (roomCount < 18) {
    node.warn('Waiting: ' + roomCount + '/20');
    return null;
}
let lastPublish = flow.get('lastPublish') || 0;
let now = Date.now();
if (now - lastPublish < 60000) { return null; }
flow.set('lastPublish', now);
let rooms = Object.values(store);
let totalTemp = 0, totalHum = 0;
rooms.forEach(function(r) {
    totalTemp += r.sensors.temperature;
    totalHum  += r.sensors.humidity;
});
let avgTemp = (totalTemp / roomCount).toFixed(2);
let avgHum  = (totalHum  / roomCount).toFixed(2);
let fStr = 'f' + String(floorId).padStart(2, '0');
msg.topic   = `campus/b01/${fStr}/status`;
msg.payload = {
    floor:           String(floorId).padStart(2, '0'),
    timestamp:       Math.floor(Date.now() / 1000),
    avg_temperature: parseFloat(avgTemp),
    avg_humidity:    parseFloat(avgHum),
    reporting_nodes: roomCount,
    status:          roomCount >= 18 ? 'Healthy' : 'Degraded'
};
return msg;

// ── Phase 3 Command Router ─────────────────────────────────
// Handles both new Phase 3 format and legacy Phase 2 format
let rawPayload = msg.payload;
if (typeof rawPayload === 'string') {
    try { rawPayload = JSON.parse(rawPayload); }
    catch(e) { node.warn('CMD: invalid JSON'); return null; }
}

// Support Phase 3 format: {command_id, target_device, action, value}
// Support Phase 2 format: {action, value}
let action = rawPayload.action || rawPayload.method || null;
let value  = rawPayload.value  || rawPayload.params || null;
if (!action) { node.warn('CMD: missing action field'); return null; }

// Generate command_id if not present (Phase 2 compatibility)
let cmdId = rawPayload.command_id || ('cmd-' + Date.now());

// Normalise to Phase 3 format
msg.payload = {
    command_id:    cmdId,
    target_device: rawPayload.target_device || msg.topic.split('/').slice(0,4).join('-'),
    action:        action.toUpperCase(),
    value:         value,
    timestamp:     Math.floor(Date.now() / 1000),
    source:        rawPayload.source || 'dashboard'
};

// Track pending commands for ACK matching
let pending = flow.get('pendingCmds') || {};
pending[cmdId] = {
    topic:   msg.topic,
    action:  action.toUpperCase(),
    value:   value,
    sent_at: Date.now()
};
flow.set('pendingCmds', pending);

return msg;

let parts = msg.topic.split('/');
let floor = parseInt(parts[2].replace('f', ''));
let roomIDStr = parts[3];
let roomNumStr = roomIDStr.replace('r', '');
let localRoom  = parseInt(roomNumStr.slice(-2));
let room_offset = localRoom - 11;
let dynamicPort = 5683 + (floor - 1) * 10 + room_offset;
msg.method = "PUT";
msg.confirmable = true;
msg.url = `coap://127.0.0.1:${dynamicPort}/${parts[2]}/${roomIDStr}/actuators/hvac`;
msg._roomIDStr = roomIDStr;
msg._parts = parts;
// CoAP request node requires string/buffer payload
if (typeof msg.payload === 'object') {
    msg.payload = JSON.stringify(msg.payload);
}
return msg;

// Publish CoAP ACK confirmation back to HiveMQ
let parts     = msg._parts || [];
let roomIDStr = msg._roomIDStr || 'unknown';
let floorId   = env.get('FLOOR');
let fStr      = 'f' + String(floorId).padStart(2, '0');
let response  = {};
if (msg.payload) {
    try {
        response = typeof msg.payload === 'string' ?
            JSON.parse(msg.payload) : msg.payload;
    } catch(e) {}
}
msg.topic   = `campus/b01/${fStr}/${roomIDStr}/response`;
msg.payload = {
    confirmed:  true,
    ack:        response.ack   || false,
    new_state:  response.new_state || null,
    command:    response.command   || null,
    timestamp:  Math.floor(Date.now() / 1000)
};
return msg;

// ── Desired State Setter ─────────────────────────────────────
// Receives desired state pushed from ThingsBoard Shared Attributes
// Topic: campus/b01/f##/<roomID>/attributes
let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch(e) { return null; }
}

// Extract room from topic
let parts    = msg.topic.split('/');
let roomID   = parts[3];  // e.g. r101
let floorId  = env.get('FLOOR');
let fStr     = 'f' + String(floorId).padStart(2, '0');
let sensorId = `b01-${fStr}-${roomID}`;

// Store desired state
let desired = flow.get('desiredState') || {};
desired[sensorId] = {
    hvac_mode:       payload.hvac_mode       || payload.desired_hvac    || null,
    lighting_dimmer: payload.lighting_dimmer || payload.desired_dimmer  || null,
    set_at:          Math.floor(Date.now() / 1000)
};
flow.set('desiredState', desired);
node.warn('DESIRED SET: ' + sensorId + ' → ' + JSON.stringify(desired[sensorId]));

// Check reported state immediately — node might already be in sync
let reported = flow.get('reportedState') || {};
let rep = reported[sensorId];
if (rep) {
    let alreadyInSync = true;
    if (desired[sensorId].hvac_mode && desired[sensorId].hvac_mode !== rep.hvac_mode) {
        alreadyInSync = false;
    }
    if (desired[sensorId].lighting_dimmer !== null &&
        desired[sensorId].lighting_dimmer !== rep.lighting_dimmer) {
        alreadyInSync = false;
    }
    if (alreadyInSync) {
        delete desired[sensorId];
        flow.set('desiredState', desired);
        node.warn('SYNC: ' + sensorId + ' already in sync — no action needed');
        return null;
    }
}

// Node not in sync — build immediate command
let d = desired[sensorId];
if (d.hvac_mode) {
    node.send([{
        topic:   `campus/b01/${fStr}/${roomID}/cmd`,
        payload: JSON.stringify({
            command_id:    'desired-' + Date.now(),
            target_device: sensorId,
            action:        'SET_HVAC',
            value:         d.hvac_mode,
            timestamp:     Math.floor(Date.now() / 1000),
            source:        'desired_state'
        })
    }, null]);
}
if (d.lighting_dimmer !== null) {
    node.send([null, {
        topic:   `campus/b01/${fStr}/${roomID}/cmd`,
        payload: JSON.stringify({
            command_id:    'desired-dimmer-' + Date.now(),
            target_device: sensorId,
            action:        'SET_DIMMER',
            value:         d.lighting_dimmer,
            timestamp:     Math.floor(Date.now() / 1000),
            source:        'desired_state'
        })
    }]);
}
return null;

// ── ACK Handler: close round-trip loop ──────────────────────
let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch(e) { return null; }
}
if (payload.ack !== true) { return null; }

let sensorId  = payload.sensor_id;
let command   = payload.command;
let new_state = payload.new_state;

node.warn('ACK: ' + sensorId + ' cmd=' + command + ' new_state=' + new_state);

// ── 1. Clear from pending commands ───────────────────────────
let pending = flow.get('pendingCmds') || {};
Object.keys(pending).forEach(function(cmdId) {
    let p = pending[cmdId];
    if (p.action === command) { delete pending[cmdId]; }
});
flow.set('pendingCmds', pending);

// ── 2. Update reported state ──────────────────────────────────
let reported = flow.get('reportedState') || {};
if (!reported[sensorId]) { reported[sensorId] = {}; }
if (command === 'SET_HVAC')   { reported[sensorId].hvac_mode       = new_state; }
if (command === 'SET_DIMMER') { reported[sensorId].lighting_dimmer = new_state; }
reported[sensorId].last_seen = Math.floor(Date.now() / 1000);
flow.set('reportedState', reported);

// ── 3. Check if desired is now satisfied ──────────────────────
let desired = flow.get('desiredState') || {};
let roomDesired = desired[sensorId];
if (roomDesired) {
    let satisfied = true;
    let rep = reported[sensorId];
    if (roomDesired.hvac_mode && roomDesired.hvac_mode !== rep.hvac_mode) {
        satisfied = false;
    }
    if (roomDesired.lighting_dimmer !== undefined &&
        roomDesired.lighting_dimmer !== rep.lighting_dimmer) {
        satisfied = false;
    }
    if (satisfied) {
        delete desired[sensorId];
        flow.set('desiredState', desired);
        node.warn('SYNC COMPLETE: ' + sensorId + ' desired == reported');
    }
}

// ── 4. Store last ack per room for dashboard ──────────────────
let acks = flow.get('lastAcks') || {};
acks[sensorId] = {
    command:   command,
    new_state: new_state,
    ts:        payload.ts_ms || Date.now()
};
flow.set('lastAcks', acks);
return msg;

let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch(e) { return null; }
}
if (payload.status === 'offline') {
    node.warn('NODE OFFLINE: ' + (payload.sensor_id || msg.topic));
    let offlineNodes = flow.get('offlineNodes') || {};
    offlineNodes[payload.sensor_id] = { since: Math.floor(Date.now() / 1000) };
    flow.set('offlineNodes', offlineNodes);
} else if (payload.status === 'online') {
    let offlineNodes = flow.get('offlineNodes') || {};
    delete offlineNodes[payload.sensor_id];
    flow.set('offlineNodes', offlineNodes);
    node.warn('NODE ONLINE: ' + payload.sensor_id);
}
return msg;
